const row   = $input.first().json;
const body  = $('Webhook').first().json.body || {};
const force = body.force === true || body.force === 'true';

if (!row.system_id) throw new Error('No se encontró ningún sistema en public.System');

const use_cache = (
  !force &&
  row.has_doc === true &&
  row.gen_status === 'completed'
);

return {
  json: {
    system_id:        row.system_id,
    system_name:      row.system_name,
    system_description: row.system_description,
    has_doc:          row.has_doc,
    doc_updated_at:   row.doc_updated_at,
    gen_status:       row.gen_status,
    use_cache,
    force
  }
};

const row  = $input.first().json;
const ctx  = $('Evalúa Caché').first().json;
return {
  json: {
    success:      true,
    from_cache:   true,
    system_id:    ctx.system_id,
    system_name:  ctx.system_name,
    functional_md: row.functional_md,
    content_html: row.content_html,
    generated_at: row.updated_at
  }
};

const agentOut   = $input.first().json;
const ctx        = $('Evalúa Caché').first().json;
const stats      = $('Recopila Estadísticas').first().json;

const functional_md = (agentOut.output || agentOut.text || '').trim();

if (!functional_md) throw new Error('El agente no retornó contenido');

// Convierte Markdown a HTML
const mdToHtml = (md) => {
  return md
    .replace(/^# (.+)$/gm,    '<h1>$1</h1>')
    .replace(/^## (.+)$/gm,   '<h2>$1</h2>')
    .replace(/^### (.+)$/gm,  '<h3>$1</h3>')
    .replace(/^#### (.+)$/gm, '<h4>$1</h4>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.+?)\*/g,    '<em>$1</em>')
    .replace(/`(.+?)`/g,      '<code>$1</code>')
    .replace(/^\| (.+) \|$/gm, (m) => '<tr>' + m.split('|').filter(c => c.trim()).map(c => `<td>${c.trim()}</td>`).join('') + '</tr>')
    .replace(/^- (.+)$/gm,    '<li>$1</li>')
    .replace(/^\d+\. (.+)$/gm, '<li>$1</li>')
    .replace(/(<li>.*<\/li>\n?)+/g,  s => `<ul>${s}</ul>`)
    .replace(/(<tr>.*<\/tr>\n?)+/g,  s => `<table>${s}</table>`)
    .replace(/\n{2,}/g, '</p><p>')
    .replace(/^(?!<[h|u|t|l|p])/gm, '');
};

const body_html = mdToHtml(functional_md);

const content_html = `<!DOCTYPE html>
<html lang="es">
<head><meta charset="UTF-8">
<title>${ctx.system_name} — Documentación Funcional del Sistema</title>
<style>
  body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;margin:0;padding:32px;max-width:960px;color:#111;line-height:1.7;}
  h1{font-size:26px;border-bottom:3px solid #059669;padding-bottom:10px;color:#064e3b;margin-bottom:8px;}
  h2{font-size:19px;margin-top:36px;color:#047857;border-bottom:1px solid #d1fae5;padding-bottom:5px;}
  h3{font-size:15px;color:#374151;margin-top:20px;}
  h4{font-size:13px;color:#6b7280;margin-top:12px;text-transform:uppercase;letter-spacing:.05em;}
  table{width:100%;border-collapse:collapse;margin:16px 0;font-size:14px;}
  td,th{border:1px solid #e5e7eb;padding:9px 14px;text-align:left;vertical-align:top;}
  tr:first-child td{background:#ecfdf5;font-weight:600;}
  tr:nth-child(even) td{background:#f9fafb;}
  code{background:#f3f4f6;padding:2px 6px;border-radius:4px;font-size:13px;font-family:'JetBrains Mono',monospace;}
  ul,ol{padding-left:22px;}
  li{margin-bottom:5px;}
  p{margin:10px 0;}
  .meta{background:#ecfdf5;border-left:4px solid #059669;padding:14px 18px;margin-bottom:28px;border-radius:4px;font-size:13px;color:#374151;display:flex;gap:24px;flex-wrap:wrap;}
  .meta span{white-space:nowrap;}
</style>
</head>
<body>
<div class="meta">
  <span><strong>Sistema:</strong> ${ctx.system_name}</span>
  <span><strong>Programas:</strong> ${stats.total_programs}</span>
  <span><strong>Líneas:</strong> ${(stats.total_lines || 0).toLocaleString('es-AR')}</span>
  <span><strong>Generado:</strong> ${new Date().toLocaleDateString('es-AR')}</span>
</div>
${body_html}
</body></html>`;

return {
  json: {
    system_id:    ctx.system_id,
    system_name:  ctx.system_name,
    functional_md,
    content_html
  }
};

const data = $('Genera HTML y Prepara Datos').first().json;
return {
  json: {
    success:       true,
    from_cache:    false,
    system_id:     data.system_id,
    system_name:   data.system_name,
    functional_md: data.functional_md,
    content_html:  data.content_html,
    generated_at:  new Date().toISOString()
  }
};
